class Solution {
public:
    int findKthNumber(int n, int k) {
        int num = 1;
        k--;
        while (k > 0) {
            int count = 0;
            for (int i = num; i <= n; i++) {
                if (i < 10) {
                    count++;
                } else {
                    count += i / 10;
                }
                if (count > k) {
                    num = i;
                    k -= count - k;
                    break;
                }
            }
        }
        return num;
    }
};
